#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=20005;
int f[N],m,n;
vector<int> v;
struct node
{
	int x,y,op;
} a[N];
unordered_map<int,int> mp;
int find(int x)
{
	if(f[x]==x) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int x,y;
		string s;
		cin>>x>>y>>s;
		x--;
		v.push_back(x);
		v.push_back(y);
		if(s[0]=='o') a[i]=node{x,y,1};
		else a[i]=node{x,y,0};
	}
	sort(v.begin(),v.end());
	int len=unique(v.begin(),v.end())-v.begin();
	for(int i=1;i<=2*len;i++) f[i]=i;
	for(int i=0;i<len;i++)
	{
		mp[v[i]]=i+1;
	}
	for(int i=1;i<=m;i++)
	{
		a[i].x=mp[a[i].x];
		a[i].y=mp[a[i].y];
//		cout<<a[i].x<<" "<<a[i].y<<" "<<a[i].op<<"\n";
		if(a[i].op==0)
		{
			if(find(a[i].x)==find(a[i].y+len))
			{
				cout<<i-1;
				return 0;
			}
			if(find(a[i].x)!=find(a[i].y))
			{
				f[find(a[i].x)]=find(a[i].y);
				f[find(a[i].x+len)]=find(a[i].y+len);
			}
		}
		else
		{
			if(find(a[i].x)==find(a[i].y))
			{
				cout<<i-1;
				return 0;
			}
			if(find(a[i].x+len)!=find(a[i].y))
			{
				f[find(a[i].x+len)]=find(a[i].y);
				f[find(a[i].x)]=find(a[i].y+len);
			}
		}
	}
	cout<<m;
	return 0;
}
